import React, { useState } from "react";
import logout from "@wasp/auth/logout.js";
import { useQuery } from "@wasp/queries";
import { useAction } from "@wasp/actions";
import getTasks from "@wasp/queries/getTasks";
import createTask from "@wasp/actions/createTask";
import updateTask from "@wasp/actions/updateTask";

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskAction = useAction(createTask);
  const updateTaskAction = useAction(updateTask);

  const [description, setDescription] = useState("");

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!description) return;
    try {
      await createTaskAction({ description });
      setDescription("");
    } catch (err: any) {
      window.alert("Error: " + err.message);
    }
  };

  const handleToggleTask = async (id: number, isDone: boolean) => {
    try {
      await updateTaskAction({ id, isDone: !isDone });
    } catch (err: any) {
      window.alert("Error: " + err.message);
    }
  };

  if (isLoading) return "Loading...";
  if (error) return "Error: " + error.message;

  return (
    <div style={{ maxWidth: "600px", margin: "0 auto", padding: "20px" }}>
      <h1>Todo List</h1>
      <button onClick={logout}>Logout</button>

      <form onSubmit={handleAddTask} style={{ margin: "20px 0" }}>
        <input
          type="text"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="New Task"
        />
        <button type="submit">Add Task</button>
      </form>

      <ul>
        {tasks?.map((task) => (
          <li key={task.id}>
            <input
              type="checkbox"
              checked={task.isDone}
              onChange={() => handleToggleTask(task.id, task.isDone)}
            />
            <span style={{ textDecoration: task.isDone ? "line-through" : "none" }}>
              {task.description}
            </span>
          </li>
        ))}
      </ul>
    </div>
  );
}

